    32→} from './models';
    33→
    34→export namespace Slices {
    35→  export type SliceMapReducer = MachineReducer & { info: MachineSliceInfo };
    36→  // prettier-ignore
    37→  export type SliceMap = {
    38→    reducer: SliceMapReducer;
    39→    actionCreatorByType: { [K in StringTypes.ActionType]: RuntimeActionCreator };
    40→    actionCreatorListBySliceKey: { [K in StringTypes.SliceKey]: RuntimeActionCreator[] };
    41→    actionCreatorsSliceKey: { [K in StringTypes.SliceKey]: { [K: string]: RuntimeActionCreator } };
    42→    actionTypesBySliceKey: { [K in StringTypes.SliceKey]: { [K: string]: string } };
    43→    reducerBySliceKey: { [K: StringTypes.SliceKey]: SliceMapReducer };
    44→    reducerByActionType: { [K in StringTypes.ActionType]: SliceMapReducer };
    45→    actionTypeList: StringTypes.ActionType[];
    46→  };
    47→
    48→  /** Explicit type for sync slice model */
    49→  export type SyncSliceModel = {
    50→    id: string;
    51→    kind: SliceKind.sync;
    52→    initial: unknown;
    53→    reducers: Record<string, SliceReducer>;
    54→    cache: CacheStrategy;
    55→  };
    56→
    57→  /** Explicit type for async slice model */
    58→  export type AsyncSliceModel = {
    59→    id: string;
    60→    kind: SliceKind.async;
    61→    initial: AsyncSliceState<unknown>;
    62→    load: (...args: any[]) => Promise<unknown>;
    63→    context: SliceContext;
    64→    cache: CacheStrategy;
    65→  };
    66→
    67→  export type SlicesMap = Omit<SliceMap, 'reducer'> & {
    68→    info: MachineSliceInfo[];
    69→    mergedSlicesInitialContext: SliceContext;
    70→    mergedSlicesInitialState: AnyRecord;
    71→  };
