   103→    assertObject(value);
   104→    return AsyncSliceModel.isValid(value);
   105→  }
   106→
   107→  export const AsyncReducerNames = new Set([
   108→    'load',
   109→    'success',
   110→    'fail',
   111→    'clear',
   112→  ] as const);
   113→
   114→  /**
   115→   * Maps one slice to internal machine utils
   116→   * @param machineID
   117→   * @param map
   118→   * @constructor
