   120→  export function MapSlice(machineID: string, map: MachineSliceInfo): SliceMap {
   121→    const { sliceKey, slice, actionPrefix } = map;
   122→    let reducer = null as SliceMapReducer | null;
   123→    const actionCreatorByType = {} as SlicesMap['actionCreatorByType'];
   124→    const reducerByActionType = {} as SlicesMap['reducerByActionType'];
   125→    // prettier-ignore
