    11→import { GLOBAL_APP_SESSION_ID } from './helpers';
    12→
    13→import {
    14→  CombineSlicesContext,
    15→  CombineSlicesState,
    16→  MachineAction,
    17→  MachineConfig,
    18→  MachineMetadata,
