   149→      const sliceKey = reducer.info.sliceKey;
   150→      const previousSliceState = rootState[sliceKey] as MachineState;
   151→      const nextSliceState = reducer(previousSliceState, action);
   152→
   153→      if (previousSliceState === nextSliceState) {
   154→        return rootState;
   155→      }
   156→
   157→      let next = {
   158→        ...rootState,
   159→        [sliceKey]: nextSliceState,
   160→      };
   161→
   162→      if (trackMetadata) {
   163→        next = UpsertStateMetadata({
   164→          currentSessionID: sessionID,
   165→          mappedSlices,
   166→          userID: getContext().userID,
   167→          operation: {
   168→            op: 'update',
   169→            state: next,
   170→            originActionType: action.type,
   171→            override: {},
   172→          },
   173→        });
   174→      }
   175→
   176→      return withSelectorValues(next);
   177→    };
   178→  }
   179→
   180→  /**
   181→   * Factory function to create a new state machine definition.
   182→   * @returns A frozen, read-only state machine definition object.
   183→   * @param config
   184→   */
