   186→    const Slices extends MachineSlices,
   187→    const Selectors extends MachineSelectors<CombineSlicesState<Slices>>,
   188→    const State extends CombineSlicesState<Slices>,
   189→    const Context extends CombineSlicesContext<Slices>,
   190→    const ID extends string,
   191→  >(
   192→    config: MachineConfig<Slices, State, Selectors, Context, ID>,
