     1→import _getProperty from 'lodash/get';
     2→import _isPlainObject from 'lodash/isPlainObject';
     3→import _setProperty from 'lodash/set';
     4→
     5→import {
     6→  assertErrorLike,
     7→  invariant,
     8→  InvariantError,
     9→  moveStackTrace,
    10→  tryCatch,
    11→} from './error-utils';
    12→
    13→import { capitalize } from './string-utils';
    14→import {
    15→  AsString,
    16→  BuiltIn,
    17→  CastUnknown,
    18→  Compute,
    19→  Falsy,
    20→  isFalsy,
    21→  ObjectEntries,
    22→  Paths,
    23→  PathType,
    24→  UnionToIntersection,
    25→  UnknownRecord,
    26→} from './type-utils';
    27→import { getTypeOf } from './typeof';
    28→
    29→/**
    30→ * Utils to handle object and object paths
    31→ * Some example of object paths:
    32→ * - considering a User object:
    33→ *  - 'user.id';
    34→ *  - 'user.address.street';
    35→ *  - 'user.address';
    36→ */
    37→
    38→/**
    39→ * extract object keys with type inference
    40→ */
    41→export function objectKeys<Obj extends object>(
    42→  value: Obj,
    43→): Extract<keyof Obj, string>[] {
    44→  try {
    45→    return Object.keys(value) as never;
    46→  } catch (e) {
    47→    assertErrorLike(e);
    48→    throw moveStackTrace(e, objectKeys);
    49→  }
    50→}
    51→
    52→export function objectEntries<O extends object>(init: O): ObjectEntries<O> {
    53→  return Object.entries(init) as never;
    54→}
    55→
    56→export function objectValues<O extends object>(init: O): O[keyof O][] {
    57→  return Object.values(init) as any;
    58→}
    59→
    60→/**
    61→ * Checks if value is a plain object, that is, an object created by the
    62→ * Object constructor or one with a [[Prototype]] of null.
    63→ */
    64→export function isObject(value: unknown): value is UnknownRecord {
    65→  return _isPlainObject(value);
    66→}
    67→
    68→export function assertObject(
    69→  value: unknown,
    70→  message?: string,
    71→  parent?: Function,
    72→): asserts value is UnknownRecord {
    73→  if (isObject(value)) return;
    74→
    75→  message =
    76→    message ??
    77→    `Expected value to be an object; found ${getTypeOf(value)} instead.`;
    78→  throw new InvariantError(message, parent ?? assertObject, { value });
    79→}
    80→
    81→/**
    82→ * Get value from an object path.
    83→ * It will assert against 'falsy' values unless configured to accept.
    84→ * Any value that matches `Boolean(value) === false` is falsy.
    85→ *
    86→ * @example:
    87→ * - getValue(value, 'user.id'); // => string;
    88→ * - getValue(value, 'user.id', true); // => string|null|undefined;
    89→ * @param object
    90→ * @param path
    91→ * @param allowFalsyValues
    92→ */
    93→
    94→export function getProperty<Obj, OPath extends Paths<Obj>>(
    95→  object: Obj,
    96→  path: CastUnknown<OPath, string>,
    97→  allowFalsyValues: false, // default mode
    98→): Exclude<PathType<Obj, OPath>, Falsy>;
    99→
   100→export function getProperty<Obj, OPath extends Paths<Obj>>(
   101→  object: Obj,
   102→  path: CastUnknown<OPath, string>,
   103→): Exclude<PathType<Obj, OPath>, Falsy>;
   104→
   105→export function getProperty<Obj, OPath extends Paths<Obj>>(
   106→  object: Obj,
   107→  path: CastUnknown<OPath, string>,
   108→  allowFalsyValues: true,
   109→): PathType<Obj, OPath> | null | undefined;
   110→
   111→export function getProperty<Obj, OPath extends Paths<Obj>>(
   112→  object: Obj,
   113→  path: CastUnknown<OPath, string>,
   114→  allowFalsyValues: boolean = false,
