     3→/**
     4→ * Creates a lazy-initialized proxy object. The thunk is executed only once,
     5→ * the first time any property of the object is accessed.
     6→ * @param thunk A function that returns the object to be lazily initialized.
     7→ * @param target
     8→ */
     9→export function createProxy<T extends object>(
    10→  thunk: () => T,
    11→  target?: object,
    12→): T {
    13→  const proxyTarget = (() => {
    14→    if (target) return target;
    15→    const draft = Object.create(null);
    16→    return Object.defineProperties(draft, {
    17→      '~whoami': {
    18→        value: 'proxy_target',
    19→        enumerable: false,
    20→      },
    21→    });
    22→  })();
    23→
    24→  let RESULT = null as unknown as T;
    25→  const resolve = () => {
