export type AssertStringOptions = {
  /** If true, also validates that the string is not empty (after trim) */
  notEmpty?: boolean;
  /** Custom error message */
  message?: string;
};

/**
 * Type guard to check if value is a string.
 */
export function isString(value: unknown): value is string {
  return typeof value === 'string';
}

/**
 * Assert that value is a string.
 * @param value - Value to check
 * @param options - Validation options
 * @throws TypeError if value is not a string or is empty (when notEmpty: true)
 *
 * @example
 * assertString(value);
 * assertString(value, { notEmpty: true });
 * assertString(value, { message: 'Name is required' });
 */
export function assertString(
  value: unknown,
  options?: AssertStringOptions,
): asserts value is string {
  if (typeof value !== 'string') {
    const message =
      options?.message ??
      `Expected string, got ${value === null ? 'null' : typeof value}`;
    throw new TypeError(message);
  }

  if (options?.notEmpty && value.trim().length === 0) {
    const message = options?.message ?? 'Expected non-empty string';
    throw new TypeError(message);
  }
}

/**
 * Capitalize the first letter of a string.
 * @throws TypeError if value is not a string
 */
export function capitalize<T extends string>(value: T): Capitalize<T> {
  assertString(value);
  return (value.charAt(0).toUpperCase() + value.slice(1)) as never;
}

