     1→import { isObject } from '../helpers/object-utils';
     2→import { UnknownRecord } from '../helpers/type-utils';
     3→import { invariantType } from '../schema';
     4→
     5→import {
     6→  MachineAction,
     7→  MachineReducer,
     8→  UnknownAction,
     9→  WithMetadata,
    10→} from './models';
    11→
    12→export namespace Store {
    13→  export type Unsubscribe = () => void;
    14→
    15→  export type ActionListener = (action: UnknownAction) => void;
    16→
    17→  export type Listener<State> = (state: State, action: MachineAction) => void;
    18→
    19→  export type Subscription<State = any> = (
    20→    listener: Listener<State>,
    21→  ) => Unsubscribe;
    22→
    23→  export type Instance<State = UnknownRecord> = {
    24→    getState(): WithMetadata<State>;
    25→    dispatch(action: any): any;
    26→    subscribe: Subscription<State>;
    27→  };
    28→
    29→  export type SetupParams<State> = {
    30→    reducer: MachineReducer<State>;
    31→    getInitialState(): State;
    32→    machineID: string;
    33→  };
    34→
    35→  export function create<State>(params: SetupParams<State>): Instance<State> {
    36→    const { getInitialState, reducer, machineID } = params;
    37→
    38→    let currentReducer = reducer;
    39→    let currentState = getInitialState();
    40→    let currentListeners: Listener<State>[] = [];
    41→
    42→    function getState() {
    43→      return currentState;
    44→    }
    45→
    46→    function subscribe(listener: Listener<State>) {
    47→      invariantType('function', listener, subscribe);
    48→      currentListeners.push(listener);
    49→
    50→      return function unsubscribe() {
    51→        const index = currentListeners.indexOf(listener);
    52→        currentListeners.splice(index, 1);
    53→      };
    54→    }
    55→
    56→    function dispatch(action: MachineAction): UnknownAction {
    57→      if (!isObject(action)) {
    58→        throw new Error('Actions must be plain objects.');
    59→      }
    60→      if (typeof action.type === 'undefined') {
    61→        throw new Error('Actions may not have an undefined "type" property.');
    62→      }
    63→
    64→      currentState = currentReducer(currentState, action);
    65→
    66→      // when listeners unsubscribe themselves during dispatch
    67→      const listeners = [...currentListeners];
    68→      for (const listener of listeners) {
    69→        listener(currentState, action);
    70→      }
    71→
    72→      return action;
    73→    }
    74→
    75→    dispatch({ type: `@@${machineID}/init` });
    76→
    77→    return {
    78→      dispatch,
