import { isValid } from 'date-fns';

/**
 * Get name of values
 * @example
 * ```ts
 *  getTypeOf({})
 * ```
 * @param value
 */
export function getTypeOf(value: any): string {
  if (value === null) return 'Null';

  if (Number.isNaN(value)) return 'NaN';

  if (value === Infinity) return 'Infinity';

  if (value instanceof Date) {
    if (isValid(value)) return 'Date';
    return 'Invalid Date';
  }

  if (typeof value?.constructor?.name === 'string') {
    return value.constructor.name;
  }

  if (typeof value === 'object') {
    // Handling objects without prototype
    return 'Object';
  }

  const tof = typeof value;

  return tof.slice(0, 1).toUpperCase() + tof.slice(1);
}

import { MSTimeString } from '../../helpers/ms';

/**
 * Defines the cache invalidation policy and scope.
 */
export enum CachePolicy {
  /**
   * Public, shared cache. Invalidated only by its TTL.
   * Ideal for global data that rarely changes.
   * E.g., Plan prices, feature flag configurations.
   */
  public = 'public',

  /**
   * Private cache, bound to the user session.
   * Invalidated on logout/login OR when TTL expires.
   * E.g., User profile data, permissions.
   */
  private = 'private',

  /**
   * App session cache. Persists while the app is active.
   * Invalidated on app close/reopen OR when TTL expires.
   * E.g., Data for a specific screen that doesn't need to persist.
   */
  session = 'session',
}

/**
 * Defines the caching behavior for a slice.
 */
export type CacheStrategy = {
  /**
   * Policy defining the cache's lifecycle and scope.
   * Cache is invalidated by the policy's event OR TTL expiry, whichever comes first.
   * @default 'private'
   */
  policy: keyof typeof CachePolicy;
  /**
   * Time-To-Live (TTL). Maximum cache lifespan (e.g., '1h', '30m').
   * A TTL of 0 means the cache expires immediately, forcing revalidation.
   */
  ttl?: MSTimeString;
  /**
   * Stale-While-Revalidate (SWR).
   * If true, returns cached data (even if stale) while revalidating in the background.
   * If false and the cache is invalid, it will wait for the fresh data fetch.
   * @default true
   */
  swr?: boolean;
};

export type CacheStrategyField = keyof CacheStrategy & {};

