import { isObject, reduceObject } from './object-utils';
import { getTypeOf } from './typeof';

/**
 * Mask a value for logging sensitive data information
 * @param value
 */
export function maskData(value: any): object {
  const loop = (looping: any): any => {
    if (Array.isArray(looping)) {
      return looping.map(el => {
        return loop(el);
      });
    }
    if (!isObject(looping)) return getTypeOf(looping);
    return reduceObject(looping, ([key, value]) => {
      return {
        [key]: loop(value),
      };
    });
  };
  return loop(value);
}

